#include <bits/stdc++.h>
using namespace std;
int n,h,t,u[51],w[51],v[51];
long long dp[51][402][402];
int main(){
    cin>>h>>t>>n;
    for(int i=1;i<=n;i++)
        cin>>u[i]>>w[i]>>v[i];
    for(int i=1;i<=n;i++)
        for(int j=1;j<=h;j++)
            for(int k=1;k<=t;k++)
                if(j>=u[i] && k>=w[i])
                    dp[i][j][k]=max(dp[i-1][j][k],dp[i-1][j-u[i]][k-w[i]]+v[i]);
                else
                    dp[i][j][k]=dp[i-1][j][k];
    cout<<dp[n][h][t];
    return 0;
}
